function sendEmailNotification({ to, subject, text, html, from = 'devops-notifications@example.com' }) {
  const apiKey = process.env.SENDGRID_API_KEY;
  if (!apiKey) {
    throw new Error('SENDGRID_API_KEY is not set');
  }

  if (!to || !subject || (!text && !html)) {
    throw new Error('Missing required email fields: to, subject, and text or html');
  }

  return fetch('https://api.sendgrid.com/v3/mail/send', {
    method: 'POST',
    headers: {
      'Authorization': `Bearer ${apiKey}`,
      'Content-Type': 'application/json'
    },
    body: JSON.stringify({
      personalizations: [{ to: [{ email: to }] }],
      from: { email: from },
      subject,
      content: [
        ...(text ? [{ type: 'text/plain', value: text }] : []),
        ...(html ? [{ type: 'text/html', value: html }] : [])
      ]
    })
  }).then(async (res) => {
    if (!res.ok) {
      const details = await res.text().catch(() => '');
      throw new Error(`SendGrid request failed: ${res.status} ${res.statusText}${details ? ` - ${details}` : ''}`);
    }
    return true;
  });
}